Base_基础配置:
!
hostname {{ hostname }}
!
clock timezone BJ add 08:00:00
!
username {{ admin_user }} privilege 15 password {{ admin_pass }}
username {{ oper_user }} privilege 5 password {{ oper_pass }}
username {{ escape_user }} privilege 15 password {{ escape_pass }}
!
no telnet server enable
!
lldp enable
spanning-tree
spanning-tree mode {{ stp_mode }}
password-recovery enable
!
vlan {{ mgmt_vlan }}
 name MGMT_Management
!
interface vlan {{ mgmt_vlan }}
 ip address {{ mgmt_ip }} {{ mgmt_mask }}
!
